module RefModule(  
    input clk,  
    input rst,  
    input [3:0] temp,  
    output reg warning  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            warning <= 0;  
        else if (temp > 4'd10)  
            warning <= 1;  
        else  
            warning <= 0;  
    end  
endmodule
